content:
{
  "sentences": [
    {
      "text": "我明天要跟朋友一起去喝咖啡。",
      "pinyin": "Wǒ míngtiān yào gēn péngyǒu yīqǐ qù hē kāfēi.",
      "pinyin_numeric": "wo3 ming2tian1 yao4 gen1 peng2you3 yi1qi3 qu4 he1 ka1fei1",
      "translation_en": "I'm going to drink coffee with a friend tomorrow.",
      "translation_ko": "저는 내일 친구와 함께 커피를 마시러 갈 거예요."
    },
    {
      "text": "我們今天晚上要去看電影。",
      "pinyin": "Wǒmen jīntiān wǎnshàng yào qù kàn diànyǐng.",
      "pinyin_numeric": "wo3men jin1tian1 wan3shang4 yao4 qu4 kan4 dian4ying3",
      "translation_en": "We're going to watch a movie tonight.",
      "translation_ko": "우리는 오늘 저녁에 영화를 보러 갈 거예요."
    },
    {
      "text": "你下個星期要跟誰見面？",
      "pinyin": "Nǐ xià ge xīngqī yào gēn shéi jiànmiàn?",
      "pinyin_numeric": "ni3 xia4 ge5 xing1qi1 yao4 gen1 shei2 jian4mian4",
      "translation_en": "Who are you meeting next week?",
      "translation_ko": "다음 주에 누구를 만날 거예요?"
    },
    {
      "text": "他今天下午要去咖啡店等我。",
      "pinyin": "Tā jīntiān xiàwǔ yào qù kāfēi diàn děng wǒ.",
      "pinyin_numeric": "ta1 jin1tian1 xia4wu3 yao4 qu4 ka1fei1 dian4 deng3 wo3",
      "translation_en": "He's going to wait for me at the coffee shop this afternoon.",
      "translation_ko": "그는 오늘 오후에 커피숍에서 저를 기다릴 거예요."
    },
    {
      "text": "我們要約在餐廳門口碰面。",
      "pinyin": "Wǒmen yào yuē zài cāntīng ménkǒu pèngmiàn.",
      "pinyin_numeric": "wo3men yao4 yue1 zai4 can1ting1 men2kou3 peng4mian4",
      "translation_en": "We're going to meet at the restaurant entrance.",
      "translation_ko": "우리는 식당 입구에서 만나기로 할 거예요."
    },
    {
      "text": "她明天早上要跟姐姐一起去逛街。",
      "pinyin": "Tā míngtiān zǎoshang yào gēn jiějie yīqǐ qù guàngjiē.",
      "pinyin_numeric": "ta1 ming2tian1 zao3shang4 yao4 gen1 jie3jie5 yi1qi3 qu4 guang4jie1",
      "translation_en": "She's going shopping with her older sister tomorrow morning.",
      "translation_ko": "그녀는 내일 아침에 언니와 함께 쇼핑하러 갈 거예요."
    },
    {
      "text": "你這個週末要跟誰一起吃飯？",
      "pinyin": "Nǐ zhège zhōumò yào gēn shéi yīqǐ chīfàn?",
      "pinyin_numeric": "ni3 zhe4ge5 zhou1mo4 yao4 gen1 shei2 yi1qi3 chi1fan4",
      "translation_en": "Who are you going to eat with this weekend?",
      "translation_ko": "이번 주말에 누구와 함께 밥을 먹을 거예요?"
    },
    {
      "text": "我們要約時間一起去看電影。",
      "pinyin": "Wǒmen yào yuē shíjiān yīqǐ qù kàn diànyǐng.",
      "pinyin_numeric": "wo3men yao4 yue1 shi2jian1 yi1qi3 qu4 kan4 dian4ying3",
      "translation_en": "We're going to arrange a time to watch a movie together.",
      "translation_ko": "우리는 시간을 정해서 함께 영화를 보러 갈 거예요."
    },
    {
      "text": "他今天晚上要跟朋友一起去聊天。",
      "pinyin": "Tā jīntiān wǎnshàng yào gēn péngyǒu yīqǐ qù liáotiān.",
      "pinyin_numeric": "ta1 jin1tian1 wan3shang4 yao4 gen1 peng2you3 yi1qi3 qu4 liao2tian1",
      "translation_en": "He's going to chat with friends tonight.",
      "translation_ko": "그는 오늘 저녁에 친구와 함께 수다를 떨러 갈 거예요."
    },
    {
      "text": "我下個星期五要跟媽媽一起去吃飯。",
      "pinyin": "Wǒ xià ge xīngqī wǔ yào gēn māma yīqǐ qù chīfàn.",
      "pinyin_numeric": "wo3 xia4 ge5 xing1qi1 wu3 yao4 gen1 ma1ma5 yi1qi3 qu4 chi1fan4",
      "translation_en": "I'm going to eat with my mom next Friday.",
      "translation_ko": "저는 다음 주 금요일에 엄마와 함께 밥을 먹으러 갈 거예요."
    }
  ]
}
